const u={0:"",1:"Satu",2:"Dua",3:"Tiga",4:"Empat",5:"Lima",6:"Enam",7:"Tujuh",8:"Delapan",9:"Sembilan",10:"Sepuluh",11:"Sebelas"};function r(i){const t=Math.floor(i);if(t<0)return"";if(t<=11)return u[t]||"";if(t<20)return`${r(t-10)} Belas`;if(t<100){const n=Math.floor(t/10),a=t%10;return`${u[n]} Puluh ${r(a)}`.trim()}if(t<200)return`Seratus ${r(t-100)}`.trim();if(t<1e3){const n=Math.floor(t/100),a=t%100;return`${u[n]} Ratus ${r(a)}`.trim()}if(t<2e3)return`Seribu ${r(t-1e3)}`.trim();if(t<1e6){const n=Math.floor(t/1e3),a=t%1e3;return`${r(n)} Ribu ${r(a)}`.trim()}if(t<1e9){const n=Math.floor(t/1e6),a=t%1e6;return`${r(n)} Juta ${r(a)}`.trim()}if(t<1e12){const n=Math.floor(t/1e9),a=t%1e9;return`${r(n)} Miliar ${r(a)}`.trim()}return String(t)}function e(i){return i===0?"Nol Rupiah":`${r(i)} Rupiah`}export{e as t};
